// ─── Add Product Modal ────────────────────────────────────────────────────
const AddProductModal = ({ onSuccess }) => {
  const [form, setForm] = useState({
    title: '', description: '', category: '', starting_price: '',
    auction_start_time: '', auction_end_time: ''
  });
  const [images, setImages] = useState([]);
  const [imagePreviews, setImagePreviews] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [pendingProduct, setPendingProduct] = useState(null);

  const MIN_IMAGES = 1;
  const MAX_IMAGES = 4;

  const handleImageChange = (e) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const combined = [...images, ...files].slice(0, MAX_IMAGES);
    if (images.length + files.length > MAX_IMAGES) {
      setError(`You can upload a maximum of ${MAX_IMAGES} images.`);
    } else {
      setError('');
    }
    setImages(combined);
    setImagePreviews(combined.map(f => URL.createObjectURL(f)));
  };

  const removeImage = (index) => {
    const updated = images.filter((_, i) => i !== index);
    setImages(updated);
    setImagePreviews(updated.map(f => URL.createObjectURL(f)));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (images.length < MIN_IMAGES) {
      setError(`Please upload at least ${MIN_IMAGES} product image.`);
      return;
    }
    if (images.length > MAX_IMAGES) {
      setError(`A maximum of ${MAX_IMAGES} images is allowed.`);
      return;
    }

    setLoading(true);
    const fd = new FormData();
    Object.entries(form).forEach(([k, v]) => fd.append(k, v));
    images.forEach(img => fd.append('images', img));
    try {
      const res = await productAPI.create(fd);
      const newProduct = res.data.product || res.data;
      const bsModal = window.bootstrap?.Modal?.getInstance(document.getElementById('addProductModal'));
      if (bsModal) bsModal.hide();
      setTimeout(() => setPendingProduct(newProduct), 400);
    } catch (err) {
      const data = err.response?.data;
      setError(typeof data === 'object' ? Object.values(data).flat().join(' ') : 'Failed to create product.');
    }
    setLoading(false);
  };

  return (
    <>
      <div className="modal fade" id="addProductModal" tabIndex="-1">
        <div className="modal-dialog modal-lg">
          <div className="modal-content">
            <div className="modal-header border-0">
              <h5 className="modal-title fw-bold">
                <i className="bi bi-plus-circle me-2" style={{ color: '#e94560' }}></i>List New Product
              </h5>
              <button type="button" className="btn-close" id="closeModal" data-bs-dismiss="modal"></button>
            </div>
            <div className="modal-body">
              <div className="alert alert-warning py-2 mb-3 d-flex align-items-center gap-2">
                <i className="bi bi-exclamation-triangle-fill"></i>
                <span className="small">
                  <strong>5% Platform Fee</strong> required after listing. If unsold, <strong>2.5%</strong> is refunded to your BidZone Wallet.
                </span>
              </div>
              {error && <div className="alert alert-danger py-2">{error}</div>}
              <form onSubmit={handleSubmit}>
                <div className="row g-3">
                  <div className="col-12">
                    <label className="form-label fw-semibold">Product Title *</label>
                    <input className="form-control" placeholder="Enter product title"
                      value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} required />
                  </div>
                  <div className="col-12">
                    <label className="form-label fw-semibold">Description *</label>
                    <textarea className="form-control" rows="3" placeholder="Describe your product"
                      value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} required />
                  </div>
                  <div className="col-6">
                    <label className="form-label fw-semibold">Category</label>
                    <input className="form-control" placeholder="e.g. Electronics, Art"
                      value={form.category} onChange={e => setForm({ ...form, category: e.target.value })} />
                  </div>
                  <div className="col-6">
                    <label className="form-label fw-semibold">Starting Price (₹) *</label>
                    <input type="number" className="form-control" min="1" step="0.01"
                      value={form.starting_price} onChange={e => setForm({ ...form, starting_price: e.target.value })} required />
                    {form.starting_price && (
                      <small className="text-muted">
                        Platform fee: <strong style={{ color: '#e94560' }}>₹{(parseFloat(form.starting_price || 0) * 0.05).toFixed(2)}</strong>
                      </small>
                    )}
                  </div>
                  <div className="col-6">
                    <label className="form-label fw-semibold">Auction Start Time *</label>
                    <input type="datetime-local" className="form-control"
                      value={form.auction_start_time} onChange={e => setForm({ ...form, auction_start_time: e.target.value })} required />
                  </div>
                  <div className="col-6">
                    <label className="form-label fw-semibold">Auction End Time *</label>
                    <input type="datetime-local" className="form-control"
                      value={form.auction_end_time} onChange={e => setForm({ ...form, auction_end_time: e.target.value })} required />
                  </div>
                  <div className="col-12">
                    <label className="form-label fw-semibold">
                      Product Images * <small className="text-muted">(Min 1, Max 4 — first image is the primary thumbnail)</small>
                    </label>
                    <input type="file" className="form-control" accept="image/*" multiple
                      onChange={handleImageChange} />
                    {imagePreviews.length > 0 && (
                      <div className="d-flex gap-2 mt-2 flex-wrap">
                        {imagePreviews.map((src, idx) => (
                          <div key={idx} className="position-relative">
                            <img src={src} alt={`preview-${idx}`} width="80" height="80"
                              style={{ objectFit: 'cover', borderRadius: '8px', border: idx === 0 ? '2px solid #e94560' : '1px solid #e0e0e0' }} />
                            {idx === 0 && (
                              <span className="badge bg-danger position-absolute top-0 start-0" style={{ fontSize: '0.6rem' }}>
                                Primary
                              </span>
                            )}
                            <button type="button" className="btn btn-sm btn-light position-absolute top-0 end-0 p-0"
                              style={{ width: '20px', height: '20px', lineHeight: '1', borderRadius: '50%' }}
                              onClick={() => removeImage(idx)}>
                              <i className="bi bi-x"></i>
                            </button>
                          </div>
                        ))}
                      </div>
                    )}
                    <small className="text-muted d-block mt-1">{images.length}/{MAX_IMAGES} images selected</small>
                  </div>
                </div>
                <div className="mt-4 d-flex gap-2">
                  <button type="submit" className="btn fw-bold px-4"
                    style={{ backgroundColor: '#e94560', color: 'white' }} disabled={loading}>
                    {loading
                      ? <span className="spinner-border spinner-border-sm"></span>
                      : <><i className="bi bi-arrow-right me-2"></i>Next: Pay Listing Fee</>}
                  </button>
                  <button type="button" className="btn btn-light" data-bs-dismiss="modal">Cancel</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      </div>

      {pendingProduct && (
        <ListingFeeModal
          product={pendingProduct}
          onPaid={onSuccess}
          onClose={() => setPendingProduct(null)}
        />
      )}
    </>
  );
};

// ─── Pickup Address Modal (Post-Creation) ────────────────────────────────
// Allows sellers to Add or Edit their pickup address after listing creation.
// Shows a 1-hour reverse countdown from listing creation time for edits.
const PickupAddressModal = ({ product, onClose, onSaved }) => {
  const [initialValues, setInitialValues] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [hasAddress, setHasAddress] = useState(false);
  const [timeLeft, setTimeLeft] = useState(null);
  const timerRef = useRef(null);

  // Compute seconds remaining within the 1-hour edit window from listing creation
  const computeTimeLeft = useCallback(() => {
    const createdAt = new Date(product.created_at).getTime();
    const deadline = createdAt + 60 * 60 * 1000; // +1 hour
    const now = Date.now();
    return Math.max(0, Math.floor((deadline - now) / 1000));
  }, [product.created_at]);

  useEffect(() => {
    const load = async () => {
      try {
        const addrRes = await productAPI.getPickupAddress(product.id);
        setInitialValues(addrRes.data);
        setHasAddress(true);
      } catch {
        setInitialValues({});
        setHasAddress(false);
      }
      setLoading(false);
    };
    load();
  }, [product.id]);

  // Start countdown only when editing (address already exists)
  useEffect(() => {
    if (!hasAddress) return;
    setTimeLeft(computeTimeLeft());
    timerRef.current = setInterval(() => {
      const secs = computeTimeLeft();
      setTimeLeft(secs);
      if (secs <= 0) clearInterval(timerRef.current);
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, [hasAddress, computeTimeLeft]);

  const formatCountdown = (secs) => {
    if (secs === null) return '';
    const m = String(Math.floor(secs / 60)).padStart(2, '0');
    const s = String(secs % 60).padStart(2, '0');
    return `${m}:${s}`;
  };

  const isExpired = hasAddress && timeLeft !== null && timeLeft <= 0;

  const handleSubmit = async (values) => {
    setSaving(true);
    setError('');
    try {
      // Use PATCH when updating an existing address, POST when creating
      if (hasAddress) {
        await productAPI.updatePickupAddress(product.id, values);
      } else {
        await productAPI.savePickupAddress(product.id, values);
      }
      setSuccess(true);
      onSaved();
      setTimeout(() => onClose(), 1800);
    } catch (err) {
      const data = err.response?.data;
      setError(typeof data === 'object' ? Object.values(data).flat().join(' ') : 'Failed to save pickup address.');
    }
    setSaving(false);
  };

  return (
    <div className="modal show d-block" tabIndex="-1" style={{ background: 'rgba(0,0,0,0.55)', zIndex: 9999 }}>
      <div className="modal-dialog modal-dialog-centered modal-lg">
        <div className="modal-content border-0 shadow-lg" style={{ borderRadius: 16 }}>
          {/* Header */}
          <div className="modal-header text-white border-0"
            style={{ background: 'linear-gradient(135deg,#1a1a2e,#0f3460)', borderRadius: '16px 16px 0 0' }}>
            <div>
              <h5 className="modal-title fw-bold mb-0">
                <i className="bi bi-geo-alt-fill me-2" style={{ color: '#e94560' }}></i>
                {hasAddress ? 'Edit Pickup Address' : 'Add Pickup Address'}
              </h5>
              <small className="opacity-75">{product.title}</small>
            </div>
            <div className="d-flex align-items-center gap-3">
              {/* Countdown badge — only shown when editing within 1h window */}
              {hasAddress && timeLeft !== null && (
                <div className={`badge fs-6 px-3 py-2 ${isExpired ? 'bg-danger' : timeLeft < 300 ? 'bg-warning text-dark' : 'bg-success'}`}
                  title="Time remaining to edit pickup address">
                  <i className="bi bi-clock me-1"></i>
                  {isExpired ? 'Window Closed' : formatCountdown(timeLeft)}
                </div>
              )}
              <button type="button" className="btn-close btn-close-white" onClick={onClose} />
            </div>
          </div>

          <div className="modal-body p-4">
            {loading ? (
              <div className="text-center py-5">
                <div className="spinner-border" style={{ color: '#e94560' }}></div>
              </div>
            ) : success ? (
              <div className="text-center py-5">
                <div style={{ width: 64, height: 64, borderRadius: '50%', background: '#28a745', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px' }}>
                  <i className="bi bi-check-lg text-white fs-2"></i>
                </div>
                <h5 className="fw-bold text-success">Pickup Address Saved!</h5>
                <p className="text-muted small">Closing automatically…</p>
              </div>
            ) : isExpired ? (
              <div className="alert alert-danger text-center py-4">
                <i className="bi bi-clock-history fs-2 d-block mb-2"></i>
                <h6 className="fw-bold">Edit Window Expired</h6>
                <p className="mb-0 small">The 1-hour edit window from listing creation has passed. Contact support if you need to update this address.</p>
              </div>
            ) : (
              <>
                {/* Info banner */}
                {hasAddress ? (
                  <div className="alert alert-warning py-2 mb-3 d-flex align-items-center gap-2 small">
                    <i className="bi bi-exclamation-triangle-fill"></i>
                    <span>
                      You can edit this pickup address within <strong>1 hour</strong> of listing creation.
                      {timeLeft !== null && timeLeft > 0 && (
                        <> Time remaining: <strong>{formatCountdown(timeLeft)}</strong></>
                      )}
                    </span>
                  </div>
                ) : (
                  <div className="alert alert-info py-2 mb-3 d-flex align-items-center gap-2 small">
                    <i className="bi bi-info-circle-fill"></i>
                    <span>Add the pickup address for this listing. Buyers will use this to arrange collection of the item.</span>
                  </div>
                )}

                {error && <div className="alert alert-danger py-2 small">{error}</div>}

                <AddressForm
                  initialValues={initialValues}
                  onSubmit={handleSubmit}
                  loading={saving}
                  submitLabel={hasAddress ? 'Update Pickup Address' : 'Save Pickup Address'}
                />
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

// ─── Add More Images Modal (Seller) ───────────────────────────────────────
const AddImagesModal = ({ product, onClose, onUploaded }) => {
  const [images, setImages] = useState([]);
  const [previews, setPreviews] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const MAX_IMAGES = 4;
  const existingCount = product?.images_count || 0;
  const remaining = Math.max(MAX_IMAGES - existingCount, 0);

  const handleFileChange = (e) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const combined = [...images, ...files].slice(0, remaining);
    if (images.length + files.length > remaining) {
      setError(`You can only add ${remaining} more image(s) (maximum ${MAX_IMAGES} total).`);
    } else {
      setError('');
    }
    setImages(combined);
    setPreviews(combined.map(f => URL.createObjectURL(f)));
  };

  const removeImage = (index) => {
    const updated = images.filter((_, i) => i !== index);
    setImages(updated);
    setPreviews(updated.map(f => URL.createObjectURL(f)));
  };

  const handleUpload = async () => {
    setError('');
    if (images.length === 0) {
      setError('Please select at least 1 image to upload.');
      return;
    }
    if (images.length > remaining) {
      setError(`You can only add ${remaining} more image(s) (maximum ${MAX_IMAGES} total).`);
      return;
    }

    setLoading(true);
    const fd = new FormData();
    images.forEach(img => fd.append('images', img));
    try {
      await productAPI.addImages(product.id, fd);
      onUploaded();
      onClose();
    } catch (err) {
      const data = err.response?.data;
      setError(typeof data === 'object' ? Object.values(data).flat().join(' ') : 'Failed to upload images.');
    }
    setLoading(false);
  };

  if (!product) return null;

  return (
    <div className="modal fade show" style={{ display: 'block', background: 'rgba(0,0,0,0.5)' }} tabIndex="-1">
      <div className="modal-dialog modal-dialog-centered">
        <div className="modal-content">
          <div className="modal-header border-0">
            <h5 className="fw-bold mb-0">
              <i className="bi bi-images me-2" style={{ color: '#e94560' }}></i>Add More Images
            </h5>
            <button type="button" className="btn-close" onClick={onClose}></button>
          </div>
          <div className="modal-body">
            <p className="text-muted small mb-2">
              <strong>{product.title}</strong> currently has {existingCount} of {MAX_IMAGES} images.
              You can add up to {remaining} more.
            </p>
            {error && <div className="alert alert-danger py-2 small">{error}</div>}
            <input type="file" className="form-control" accept="image/*" multiple
              disabled={remaining <= 0}
              onChange={handleFileChange} />
            {previews.length > 0 && (
              <div className="d-flex gap-2 mt-3 flex-wrap">
                {previews.map((src, idx) => (
                  <div key={idx} className="position-relative">
                    <img src={src} alt={`new-${idx}`} width="80" height="80"
                      style={{ objectFit: 'cover', borderRadius: '8px', border: '1px solid #e0e0e0' }} />
                    <button type="button" className="btn btn-sm btn-light position-absolute top-0 end-0 p-0"
                      style={{ width: '20px', height: '20px', lineHeight: '1', borderRadius: '50%' }}
                      onClick={() => removeImage(idx)}>
                      <i className="bi bi-x"></i>
                    </button>
                  </div>
                ))}
              </div>
            )}
            <small className="text-muted d-block mt-2">{images.length}/{remaining} new image(s) selected</small>
          </div>
          <div className="modal-footer border-0">
            <button type="button" className="btn btn-light" onClick={onClose}>Cancel</button>
            <button type="button" className="btn fw-bold"
              style={{ backgroundColor: '#e94560', color: 'white' }}
              disabled={loading || remaining <= 0 || images.length === 0}
              onClick={handleUpload}>
              {loading
                ? <span className="spinner-border spinner-border-sm"></span>
                : <><i className="bi bi-upload me-2"></i>Upload</>}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

// ─── Main ─────────────────────────────────────────────────────────────────
const SellerDashboard = () => {
  const [products, setProducts] = useState([]);
  const [wallet, setWallet] = useState(null);
  const [loading, setLoading] = useState(true);
  const [imageModalProduct, setImageModalProduct] = useState(null);
  const [addressModalProduct, setAddressModalProduct] = useState(null);
  const [productAddresses, setProductAddresses] = useState({}); // { productId: addressObj|null }
  const [, setTick] = useState(0); // forces re-render every second for live countdowns

  useEffect(() => {
    const id = setInterval(() => setTick(t => t + 1), 1000);
    return () => clearInterval(id);
  }, []);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const [pRes, wRes] = await Promise.all([
        productAPI.myProducts(),
        walletAPI.myWallet(),
      ]);
      const prods = pRes.data.results || pRes.data;
      setProducts(prods);
      setWallet(wRes.data);

      // Fetch pickup address status for each product (parallel, ignore errors)
      const addressMap = {};
      await Promise.allSettled(
        prods.map(async (p) => {
          try {
            const res = await productAPI.getPickupAddress(p.id);
            addressMap[p.id] = res.data;
          } catch {
            addressMap[p.id] = null; // no address yet
          }
        })
      );
      setProductAddresses(addressMap);
    } catch { }
    setLoading(false);
  };

  useEffect(() => { fetchProducts(); }, []);

  const stats = {
    total: products.length,
    active: products.filter(p => p.status === 'ACTIVE').length,
    closed: products.filter(p => p.status === 'CLOSED').length,
    pending: products.filter(p => p.status === 'PENDING').length,
  };

  return (
    <div className="min-vh-100" style={{ background: '#f0f2f5' }}>
      <div className="py-4 text-white" style={{ background: 'linear-gradient(135deg, #1a1a2e, #0f3460)' }}>
        <div className="container">
          <div className="d-flex justify-content-between align-items-center flex-wrap gap-3">
            <div>
              <h2 className="fw-bold mb-1"><i className="bi bi-shop me-2" style={{ color: '#e94560' }}></i>Seller Dashboard</h2>
              <p className="mb-0 opacity-75">Manage your auction listings</p>
            </div>
            <div className="d-flex gap-2 align-items-center">
              {wallet && (
                <Link to="/wallet" className="btn btn-outline-light btn-sm fw-semibold" style={{ borderRadius: 20 }}>
                  <i className="bi bi-wallet2 me-1" style={{ color: '#e94560' }}></i>
                  ₹{parseFloat(wallet.balance).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                </Link>
              )}
              <button className="btn fw-bold" data-bs-toggle="modal" data-bs-target="#addProductModal"
                style={{ backgroundColor: '#e94560', color: 'white', borderRadius: '8px' }}>
                <i className="bi bi-plus-lg me-2"></i>List New Product
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="container py-4">
        <div className="row g-3 mb-4">
          {[
            { label: 'Total Listed', val: stats.total, icon: 'bi-collection', color: '#0f3460' },
            { label: 'Active Now', val: stats.active, icon: 'bi-lightning-fill', color: '#28a745' },
            { label: 'Pending', val: stats.pending, icon: 'bi-clock', color: '#ffc107' },
            { label: 'Closed', val: stats.closed, icon: 'bi-check-circle', color: '#6c757d' },
          ].map((s, i) => (
            <div key={i} className="col-6 col-md-3">
              <div className="card border-0 shadow-sm text-center p-3" style={{ borderRadius: '12px' }}>
                <i className={`bi ${s.icon} fs-2 mb-1`} style={{ color: s.color }}></i>
                <h4 className="fw-bold mb-0">{s.val}</h4>
                <small className="text-muted">{s.label}</small>
              </div>
            </div>
          ))}
        </div>

        {/* Wallet Quick Card */}
        <div className="card border-0 shadow-sm mb-4 p-4" style={{ borderRadius: '16px', background: 'linear-gradient(135deg,#1a1a2e,#0f3460)', color: '#fff' }}>
          <div className="d-flex justify-content-between align-items-center flex-wrap gap-3">
            <div>
              <div className="opacity-75 small mb-1"><i className="bi bi-wallet2 me-2"></i>BidZone Wallet Balance</div>
              <h3 className="fw-bold mb-0" style={{ color: '#4caf50' }}>
                ₹{wallet ? parseFloat(wallet.balance).toLocaleString('en-IN', { minimumFractionDigits: 2 }) : '0.00'}
              </h3>
              <small className="opacity-75">Sale proceeds are credited here. Withdraw via UPI anytime.</small>
            </div>
            <Link to="/wallet" className="btn fw-bold px-4"
              style={{ backgroundColor: '#e94560', color: 'white', borderRadius: 10 }}>
              <i className="bi bi-bank me-2"></i>Withdraw to Bank
            </Link>
          </div>
        </div>

        {/* Products Table */}
        <div className="card border-0 shadow-sm" style={{ borderRadius: '12px' }}>
          <div className="card-header bg-white border-0 p-4">
            <h5 className="fw-bold mb-0">My Products</h5>
          </div>
          <div className="card-body p-0">
            {loading ? (
              <div className="text-center py-5"><div className="spinner-border" style={{ color: '#e94560' }}></div></div>
            ) : products.length === 0 ? (
              <div className="text-center py-5">
                <i className="bi bi-box fs-1 text-muted"></i>
                <h5 className="mt-3 text-muted">No products listed yet</h5>
                <p className="text-muted small">List your first product. A 5% platform fee is required to activate.</p>
                <button className="btn mt-2" data-bs-toggle="modal" data-bs-target="#addProductModal"
                  style={{ backgroundColor: '#e94560', color: 'white' }}>
                  List Your First Product
                </button>
              </div>
            ) : (
              <div className="table-responsive">
                <table className="table table-hover mb-0">
                  <thead className="table-light">
                    <tr>
                      <th>Product</th>
                      <th>Category</th>
                      <th>Starting Price</th>
                      <th>Fee Paid (5%)</th>
                      <th>Current Bid</th>
                      <th>End Time</th>
                      <th>Status</th>
                      <th>Pickup Address</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {products.map(p => (
                      <tr key={p.id}>
                        <td>
                          <div className="d-flex align-items-center gap-3">
                            <img src={getImageUrl(p.image)} alt={p.title} width="60" height="60"
                              style={{ borderRadius: '8px', objectFit: 'cover', border: '1px solid #e0e0e0', flexShrink: 0 }} />
                            <span className="fw-semibold">{p.title}</span>
                          </div>
                        </td>
                        <td><small className="text-muted">{p.category || '-'}</small></td>
                        <td>₹{parseFloat(p.starting_price).toLocaleString()}</td>
                        <td>
                          <span className="badge bg-warning text-dark">
                            ₹{(parseFloat(p.starting_price) * 0.05).toFixed(2)}
                          </span>
                        </td>
                        <td className="fw-bold" style={{ color: '#e94560' }}>
                          ₹{parseFloat(p.current_highest_bid || p.starting_price).toLocaleString()}
                        </td>
                        <td><small>{new Date(p.auction_end_time).toLocaleString()}</small></td>
                        <td><StatusBadge status={p.status} /></td>
                        <td>
                          {(() => {
                            const addr = productAddresses[p.id];
                            const hasAddr = addr !== null && addr !== undefined;
                            const listingFeePaid = true; // fetching only seller's own products; fee status tracked server-side
                            const createdAt = new Date(p.created_at).getTime();
                            const editDeadline = createdAt + 60 * 60 * 1000;
                            const withinWindow = Date.now() < editDeadline;
                            const secsLeft = Math.max(0, Math.floor((editDeadline - Date.now()) / 1000));
                            const mmss = `${String(Math.floor(secsLeft / 60)).padStart(2,'0')}:${String(secsLeft % 60).padStart(2,'0')}`;

                            if (!hasAddr) {
                              return (
                                <button
                                  className="btn btn-sm btn-outline-success"
                                  title="Add pickup address for this listing"
                                  onClick={() => setAddressModalProduct(p)}>
                                  <i className="bi bi-geo-alt me-1"></i>Add Address
                                </button>
                              );
                            }
                            if (withinWindow) {
                              return (
                                <button
                                  className="btn btn-sm btn-outline-warning"
                                  title={`Edit pickup address — ${mmss} remaining`}
                                  onClick={() => setAddressModalProduct(p)}>
                                  <i className="bi bi-pencil me-1"></i>
                                  Edit Address
                                  <span className="badge bg-warning text-dark ms-1" style={{fontSize:'0.65rem'}}>{mmss}</span>
                                </button>
                              );
                            }
                            return (
                              <span className="badge bg-success text-white" title="Pickup address saved">
                                <i className="bi bi-geo-alt-fill me-1"></i>Address Set
                              </span>
                            );
                          })()}
                        </td>
                        <td>
                          <Link to={`/products/${p.id}`} className="btn btn-sm btn-outline-primary me-1">
                            <i className="bi bi-eye"></i>
                          </Link>
                          {(p.images_count || 0) < 4 && (
                            <button type="button" className="btn btn-sm btn-outline-secondary"
                              title="Add more images"
                              onClick={() => setImageModalProduct(p)}>
                              <i className="bi bi-images"></i>
                            </button>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>

        {/* Policy Cards */}
        <div className="row g-3 mt-2">
          {[
            { icon: 'bi-currency-rupee', color: '#e94560', title: '5% Listing Fee', text: 'Paid when listing. Goes to BidZone platform account immediately.' },
            { icon: 'bi-arrow-return-left', color: '#28a745', title: '2.5% Refund if Unsold', text: 'If auction closes with no buyer, 2.5% is refunded to your BidZone Wallet.' },
            { icon: 'bi-bank', color: '#0f3460', title: 'Instant Wallet Credit', text: 'When buyer pays, full winning amount is credited instantly. Withdraw via UPI.' },
          ].map((c, i) => (
            <div key={i} className="col-md-4">
              <div className="card border-0 shadow-sm p-3" style={{ borderRadius: 12 }}>
                <div className="d-flex align-items-center gap-2 mb-2">
                  <i className={`bi ${c.icon} fs-4`} style={{ color: c.color }}></i>
                  <h6 className="fw-bold mb-0">{c.title}</h6>
                </div>
                <p className="text-muted small mb-0">{c.text}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      <AddProductModal onSuccess={fetchProducts} />

      {imageModalProduct && (
        <AddImagesModal
          product={imageModalProduct}
          onClose={() => setImageModalProduct(null)}
          onUploaded={fetchProducts}
        />
      )}

      {addressModalProduct && (
        <PickupAddressModal
          product={addressModalProduct}
          onClose={() => setAddressModalProduct(null)}
          onSaved={fetchProducts}
        />
      )}
    </div>
  );
};

export default SellerDashboard;
